text:
This is due to ether_gen_addr() using if_name(), most likely.

Try this:
diff --git a/if_re.c b/if_re.c
index 541af57..95da310 100644
--- a/if_re.c
+++ b/if_re.c
@@ -4978,6 +4978,24 @@ static int re_attach(device_t dev)
         re_reset(sc);
         RE_UNLOCK(sc);

+#if OS_VER < VERSION(6,0)
+        ifp = &sc->arpcom.ac_if;
+#else
+        ifp = sc->re_ifp = if_alloc(IFT_ETHER);
+        if (ifp == NULL) {
+                device_printf(dev, "can not if_alloc()\n");
+                error = ENOSPC;
+                goto fail;
+        }
+#endif
+        ifp->if_softc = sc;
+#if OS_VER < VERSION(5,3)
+        ifp->if_unit = unit;
+        ifp->if_name = "re";
+#else
+        if_initname(ifp, device_get_name(dev), device_get_unit(dev));
+#endif
+
         /* Get station address. */
         RE_LOCK(sc);
         re_get_hw_mac_address(sc, eaddr);
@@ -5076,23 +5094,6 @@ static int re_attach(device_t dev)
         sc->re_tx_cstag =1;
         sc->re_rx_cstag =1;

-#if OS_VER < VERSION(6,0)
-        ifp = &sc->arpcom.ac_if;
-#else
-        ifp = sc->re_ifp = if_alloc(IFT_ETHER);
-        if (ifp == NULL) {
-                device_printf(dev, "can not if_alloc()\n");
-                error = ENOSPC;
-                goto fail;
-        }
-#endif
-        ifp->if_softc = sc;
-#if OS_VER < VERSION(5,3)
-        ifp->if_unit = unit;
-        ifp->if_name = "re";
-#else
-        if_initname(ifp, device_get_name(dev), device_get_unit(dev));
-#endif
         ifp->if_mtu = ETHERMTU;
         ifp->if_flags = IFF_BROADCAST | IFF_SIMPLEX | IFF_MULTICAST;
         ifp->if_ioctl = re_ioctl;
